pub struct ProjectAuth {
    pub project: String,
}

impl FromRequestParts<Arc<AppState>> for ProjectAuth {
    type Rejection = (StatusCode, String);

    async fn from_request_parts(
        parts: &mut Parts,
        state: &Arc<AppState>,
    ) -> Result<Self, Self::Rejection> {
        let project = parts
            .headers
            .get("x-project")
            .and_then(|v| v.to_str().ok())
            .ok_or((StatusCode::BAD_REQUEST, "Missing X-Project header".to_string()))?;
        let key = parts
            .headers
            .get("x-project-key")
            .and_then(|v| v.to_str().ok())
            .ok_or((StatusCode::BAD_REQUEST, "Missing X-Project-Key header".to_string()))?;
        if !state.broker.repo.verify_project_key(project, key) {
            return Err((StatusCode::UNAUTHORIZED, "Invalid project key".to_string()));
        }
        // F7-E: suspend check is a distinct gate from key verification ΓÇö 403 not 401
        if state.broker.repo.is_project_suspended(project) {
            return Err((StatusCode::FORBIDDEN, "Project is suspended".to_string()));
        }
        Ok(ProjectAuth {
            project: project.to_string(),
        })
    }
}

pub struct AgentAuth {
    pub project: String,
    pub agent_name: String,
}

impl FromRequestParts<Arc<AppState>> for AgentAuth {
    type Rejection = (StatusCode, String);

    async fn from_request_parts(
        parts: &mut Parts,
        state: &Arc<AppState>,
    ) -> Result<Self, Self::Rejection> {
        // Reuse ProjectAuth for project + key verification
        let ProjectAuth { project } = ProjectAuth::from_request_parts(parts, state).await?;

        let agent_name = parts
            .headers
            .get("x-agent-name")
            .and_then(|v| v.to_str().ok())
            .ok_or((StatusCode::BAD_REQUEST, "Missing X-Agent-Name header".to_string()))?;

        if !state.broker.repo.agent_exists(agent_name, &project) {
            return Err((
                StatusCode::FORBIDDEN,
                format!("Agent '{}' not registered in project '{}'", agent_name, project),
            ));
        }

        Ok(AgentAuth {
            project,
            agent_name: agent_name.to_string(),
        })
    }
}

impl FromRequestParts<Arc<AppState>> for AdminAuth {
    type Rejection = (StatusCode, String);

    async fn from_request_parts(
        parts: &mut Parts,
        state: &Arc<AppState>,
    ) -> Result<Self, Self::Rejection> {
        let expected = state.config.admin_key.as_deref().ok_or((
            StatusCode::SERVICE_UNAVAILABLE,
            "Admin API is disabled (BROKER_ADMIN_KEY not configured)".to_string(),
        ))?;
        let provided = parts
            .headers
            .get("x-admin-key")
            .and_then(|v| v.to_str().ok())
            .ok_or((StatusCode::BAD_REQUEST, "Missing X-Admin-Key header".to_string()))?;
        if provided != expected {
            return Err((StatusCode::UNAUTHORIZED, "Invalid admin key".to_string()));
        }
        Ok(AdminAuth)
    }
}

pub struct ProjectRateLimiter {
    inner: DefaultKeyedRateLimiter<String>,
}

impl ProjectRateLimiter {
    pub fn new(rps: u32) -> Self {
        let quota = Quota::per_second(
            NonZeroU32::new(rps.max(1)).expect("rps must be > 0"),
        );
        Self { inner: RateLimiter::keyed(quota) }
    }

    /// Returns true if the request is allowed, false if rate-limited.
    pub fn check(&self, project: &str) -> bool {
        self.inner.check_key(&project.to_string()).is_ok()
    }
}

pub async fn rate_limit_middleware(
    axum::extract::State(state): axum::extract::State<Arc<crate::api::routes::AppState>>,
    request: axum::extract::Request,
    next: Next,
) -> Response {
    let project = request
        .headers()
        .get("x-project")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");

    if !project.is_empty() && !state.rate_limiter.check(project) {
        tracing::debug!("Rate limit exceeded for project '{}'", project);
        return (
            StatusCode::TOO_MANY_REQUESTS,
            [(axum::http::header::RETRY_AFTER, "1")],
            "Rate limit exceeded ΓÇö retry after 1 second",
        )
            .into_response();
    }

    next.run(request).await
}

mod tests {
    use super::*;

    #[test]
    fn rate_limiter_allows_first_then_blocks() {
        // rps=1: the first call must succeed, the second (in the same second) must fail.
        // This simulates the WS path: over-limit stanza receives an error frame, not delivery.
        let limiter = ProjectRateLimiter::new(1);
        assert!(limiter.check("proj-a"), "first request must be allowed");
        assert!(!limiter.check("proj-a"), "second request in same second must be rate-limited");
    }

    #[test]
    fn rate_limiter_buckets_are_per_project() {
        // Each project has its own independent quota bucket.
        let limiter = ProjectRateLimiter::new(1);
        assert!(limiter.check("proj-a"), "proj-a first request allowed");
        assert!(!limiter.check("proj-a"), "proj-a second request blocked");
        // proj-b has a fresh bucket ΓÇö must not be affected by proj-a exhaustion
        assert!(limiter.check("proj-b"), "proj-b first request must be allowed independently");
    }
}

pub async fn handle_ws(
    ws: WebSocketUpgrade,
    State(state): State<Arc<AppState>>,
) -> impl IntoResponse {
    ws.on_upgrade(move |socket| handle_connection(socket, state))
}

pub enum WsEnvelope {
    /// Legacy: Client ΓåÆ Broker: authenticate with project key.
    /// Deprecated ΓÇö agents should register a public key and use Hello.
    Connect {
        name: String,
        project: String,
        project_key: String,
    },
    /// New: Client ΓåÆ Broker: initiate Ed25519 challenge-response handshake.
    Hello {
        name: String,
        project: String,
    },
    /// Broker ΓåÆ Client: challenge bytes for Ed25519 signing.
    Challenge {
        /// 32-byte nonce as lowercase hex string.
        nonce: String,
        /// Unix timestamp (seconds) when challenge was issued. Client includes in signed payload.
        timestamp: u64,
        /// Connection-scoped session UUID. Included in signed payload.
        session_id: String,
    },
    /// New: Client ΓåÆ Broker: signed challenge response.
    Auth {
        /// Ed25519 signature over canonical payload as lowercase hex string.
        signature: String,
    },
    /// Broker ΓåÆ Client: auth success + pending count.
    Connected {
        session_id: String,
        pending_count: usize,
    },
    /// Broker ΓåÆ Client: error notification.
    Error {
        message: String,
        /// Structured error code for machine-readable handling. None for non-auth errors.
        /// AUTH_WRONG_KEY  ΓÇö wrong private key (config error).
        /// AUTH_STALE      ΓÇö nonce expired or clock skew (retry).
        /// AUTH_INVALID_CREDS ΓÇö project key wrong or agent not found.
        #[serde(skip_serializing_if = "Option::is_none")]
        error_code: Option<String>,
    },
}

async fn handle_connection(socket: WebSocket, state: Arc<AppState>) {
    let (mut sender, mut receiver) = socket.split();

    let (name, project, session_id) = match wait_for_connect(&mut sender, &mut receiver, &state).await {
        Some(info) => info,
        None => return, // error already sent inside auth helpers
    };

    // Register live connection FIRST ΓÇö so messages arriving during pending drain are buffered in rx
    let mut rx = state.broker.connect(&name, &project).await;

    // Drain pending messages ΓÇö each body is raw stanza XML
    let pending = state.delivery.drain_pending(&name, &project);
    let pending_count = pending.len();

    let connected = WsEnvelope::Connected {
        session_id: session_id.clone(),
        pending_count,
    };
    if sender.send(Message::Text(serde_json::to_string(&connected).unwrap().into())).await.is_err() {
        return;
    }

    // Send each pending message as a raw stanza XML frame
    for msg in pending {
        if sender.send(Message::Text(msg.body.into())).await.is_err() {
            return;
        }
    }

    // mpsc channel: recv_task sends error frames back to send_task for delivery to client
    let (err_tx, mut err_rx) = tokio::sync::mpsc::channel::<String>(8);

    // Forward live messages and error frames to the client
    let mut send_task = tokio::spawn(async move {
        loop {
            tokio::select! {
                result = rx.recv() => match result {
                    Ok(msg) => {
                        if sender.send(Message::Text(msg.into())).await.is_err() {
                            tracing::warn!("WS send error ΓÇö send_task exiting");
                            break;
                        }
                    }
                    Err(_) => break,
                },
                Some(err_msg) = err_rx.recv() => {
                    if sender.send(Message::Text(err_msg.into())).await.is_err() {
                        tracing::warn!("WS send error on error frame ΓÇö send_task exiting");
                        break;
                    }
                }
            }
        }
    });

    let broker = state.broker.clone();
    let delivery = state.delivery.clone();
    let rate_limiter = state.rate_limiter.clone();
    let agent_name = name.clone();
    let agent_project = project.clone();

    // Receive stanza XML from client
    let mut recv_task = tokio::spawn(async move {
        while let Some(Ok(msg)) = receiver.next().await {
            match msg {
                Message::Text(text) => {
                    // Rate-limit per project ΓÇö same bucket as HTTP write-path routes.
                    // Drop the stanza and send an error frame; keep the connection alive.
                    if !rate_limiter.check(&agent_project) {
                        tracing::debug!("WS rate limit exceeded for project '{}'", agent_project);

// continued: async fn handle_connection(socket: WebSocket, state: Arc<AppState>) {
                        let msg = WsEnvelope::Error { message: "Rate limit exceeded".to_string(), error_code: None };
                        let _ = err_tx.try_send(serde_json::to_string(&msg).unwrap_or_default());
                        continue;
                    }
                    handle_stanza(&text, &agent_name, &agent_project, &broker, &delivery, &err_tx).await;
                }
                Message::Close(_) => break,
                _ => {}
            }
        }
    });

    tokio::select! {
        _ = &mut send_task => { recv_task.abort(); }
        _ = &mut recv_task => { send_task.abort(); }
    }

    state.broker.disconnect(&name, &project).await;
    tracing::info!("WebSocket closed: {}.{}", name, project);
}

async fn wait_for_connect(
    sender: &mut futures::stream::SplitSink<WebSocket, Message>,
    receiver: &mut futures::stream::SplitStream<WebSocket>,
    state: &Arc<AppState>,
) -> Option<(String, String, String)> {
    let text = recv_text(receiver).await?;
    match serde_json::from_str::<WsEnvelope>(&text).ok()? {
        WsEnvelope::Hello { name, project } => {
            handle_hello_auth(sender, receiver, state, name, project).await
        }
        WsEnvelope::Connect { name, project, project_key } => {
            handle_legacy_auth(sender, state, name, project, project_key).await
        }
        _ => {
            // Unexpected envelope type ΓÇö client sent something that isn't Hello or Connect.
            // Send a structured error so the client can distinguish protocol violations from drops.
            let _ = send_envelope(sender, &WsEnvelope::Error {
                message: "Expected Hello or Connect envelope to initiate connection".to_string(),
                error_code: Some("PROTOCOL_ERROR".to_string()),
            }).await;
            None
        }
    }
}

async fn recv_text(receiver: &mut futures::stream::SplitStream<WebSocket>) -> Option<String> {
    while let Some(Ok(msg)) = receiver.next().await {
        match msg {
            Message::Text(t) => return Some(t.to_string()),
            Message::Close(_) => return None,
            _ => continue,
        }
    }
    None
}

async fn send_envelope(
    sender: &mut futures::stream::SplitSink<WebSocket, Message>,
    env: &WsEnvelope,
) -> bool {
    match serde_json::to_string(env) {
        Ok(json) => sender.send(Message::Text(json.into())).await.is_ok(),
        Err(_) => false,
    }
}

async fn handle_hello_auth(
    sender: &mut futures::stream::SplitSink<WebSocket, Message>,
    receiver: &mut futures::stream::SplitStream<WebSocket>,
    state: &Arc<AppState>,
    name: String,
    project: String,
) -> Option<(String, String, String)> {
    // Agent must exist
    if !state.broker.repo.agent_exists(&name, &project) {
        tracing::warn!("Hello from unregistered agent {}.{}", name, project);
        let _ = send_envelope(sender, &WsEnvelope::Error {
            message: "Agent not registered".to_string(),
            error_code: Some("AUTH_INVALID_CREDS".to_string()),
        }).await;
        return None;
    }

    // Must have a public key ΓÇö no silent fallback within the Hello path
    let pubkey_hex = match state.broker.repo.get_agent_public_key(&name, &project) {
        Some(k) => k,
        None => {
            tracing::warn!(
                "Hello from {}.{} ΓÇö no public key registered. Use Connect for project-key auth.",
                name, project
            );
            let _ = send_envelope(sender, &WsEnvelope::Error {
                message: "No public key registered ΓÇö use project-key auth (Connect)".to_string(),
                error_code: Some("AUTH_INVALID_CREDS".to_string()),
            }).await;
            return None;
        }
    };

    // Issue challenge
    let session_id = uuid::Uuid::new_v4().to_string();
    let (nonce_bytes, _payload, timestamp) = state.broker.nonce_store.issue(&session_id, &name, &project);
    let nonce_hex = hex::encode(nonce_bytes);

    if !send_envelope(sender, &WsEnvelope::Challenge {
        nonce: nonce_hex.clone(),
        timestamp,
        session_id: session_id.clone(),
    }).await {
        return None;
    }

    // Receive Auth response
    let auth_text = recv_text(receiver).await?;
    let signature_hex = match serde_json::from_str::<WsEnvelope>(&auth_text).ok()? {
        WsEnvelope::Auth { signature } => signature,
        _ => return None,
    };

    // Consume nonce ΓÇö retrieves stored canonical payload; None means expired
    let payload = match state.broker.nonce_store.consume(&nonce_hex) {
        Some(p) => p,
        None => {
            tracing::warn!("Stale nonce from {}.{}", name, project);
            let _ = send_envelope(sender, &WsEnvelope::Error {
                message: "Challenge expired ΓÇö reconnect and retry".to_string(),
                error_code: Some("AUTH_STALE".to_string()),
            }).await;
            return None;
        }
    };

    // Verify signature
    match crate::identity::verify_agent_signature(&pubkey_hex, &payload, &signature_hex) {
        Ok(()) => {
            tracing::info!("Ed25519 auth: {}.{} authenticated", name, project);
            Some((name, project, session_id))
        }
        Err(_) => {
            tracing::warn!("Bad signature from {}.{}", name, project);
            let _ = send_envelope(sender, &WsEnvelope::Error {

// continued: async fn handle_hello_auth(
                message: "Signature verification failed ΓÇö wrong private key".to_string(),
                error_code: Some("AUTH_WRONG_KEY".to_string()),
            }).await;
            None
        }
    }
}

async fn handle_legacy_auth(
    sender: &mut futures::stream::SplitSink<WebSocket, Message>,
    state: &Arc<AppState>,
    name: String,
    project: String,
    project_key: String,
) -> Option<(String, String, String)> {
    tracing::warn!(
        "Deprecated project-key WS auth for {}.{} ΓÇö register a public key via POST /agents/register",
        name, project
    );
    if let Err(reason) = state.broker.authenticate(&name, &project, &project_key) {
        tracing::warn!("Legacy auth failed for {}.{}: {}", name, project, reason);
        let _ = send_envelope(sender, &WsEnvelope::Error {
            message: reason,
            error_code: Some("AUTH_INVALID_CREDS".to_string()),
        }).await;
        return None;
    }
    let session_id = uuid::Uuid::new_v4().to_string();
    tracing::info!("WS connected (legacy auth): {}.{}", name, project);
    Some((name, project, session_id))
}

async fn handle_stanza(
    text: &str,
    agent_name: &str,
    agent_project: &str,
    broker: &Arc<BrokerState>,
    delivery: &Arc<DeliveryEngine>,
    err_tx: &tokio::sync::mpsc::Sender<String>,
) {
    let parsed = match stanza::parse(text) {
        Ok(s) => s,
        Err(e) => {
            tracing::warn!("Invalid stanza from {}.{}: {}", agent_name, agent_project, e);
            let msg = WsEnvelope::Error { message: format!("Invalid stanza: {e}"), error_code: None };
            let _ = err_tx.try_send(serde_json::to_string(&msg).unwrap_or_default());
            return;
        }
    };

    // Accept both 'Name' and 'Name.Project' ΓÇö reject only true spoofing
    let stanza_from = match &parsed {
        stanza::Stanza::Message(msg) => msg.from.as_str(),
        stanza::Stanza::Presence(p) => p.from.as_str(),
    };
    let (stanza_name, _) = stanza::resolve_agent_name(stanza_from, agent_project);
    if stanza_name != agent_name {
        tracing::warn!(
            "Stanza 'from' mismatch: stanza says '{}', authenticated as '{}'",
            stanza_from, agent_name
        );
        let msg = WsEnvelope::Error {
            message: "Stanza 'from' does not match authenticated identity".to_string(),
            error_code: None,
        };
        let _ = err_tx.try_send(serde_json::to_string(&msg).unwrap_or_default());
        return;
    }

    // WS dispatch doesn't validate target existence (broker stores for offline agents)
    if let Err(e) = dispatch_stanza(parsed, agent_project, broker, delivery, false).await {
        match e {
            crate::broker::DispatchError::DeliveryFailed(reason) => {
                tracing::error!("Delivery failed for {}.{}: {}", agent_name, agent_project, reason);
            }
            crate::broker::DispatchError::AmbiguousMention { name, projects } => {
                let msg = WsEnvelope::Error {
                    message: format!(
                        "Mention @{} is ambiguous: found in projects [{}]. Use Name.Project to disambiguate.",
                        name,
                        projects.join(", ")
                    ),
                    error_code: None,
                };
                let _ = err_tx.try_send(serde_json::to_string(&msg).unwrap_or_default());
            }
            _ => {}
        }
    }
}

async fn spawn_test_server() -> (SocketAddr, Arc<AppState>) {
    let repo = Arc::new(db::open_memory().expect("in-memory DB"));
    let broker = Arc::new(BrokerState::new(repo));
    let delivery = Arc::new(DeliveryEngine::new(broker.clone()));
    let config = BrokerConfig {
        admin_key: None,
        rate_limit_rps: 100,
    };
    let rate_limiter = Arc::new(ProjectRateLimiter::new(100));
    let state = Arc::new(AppState {
        broker,
        delivery,
        config,
        rate_limiter,
    });

    let listener = tokio::net::TcpListener::bind("127.0.0.1:0")
        .await
        .expect("bind random port");
    let addr = listener.local_addr().expect("local_addr");

    let app = api::http_router(state.clone())
        .route("/ws", axum::routing::get(api::handle_ws))
        .with_state(state.clone());

    tokio::spawn(async move {
        axum::serve(listener, app).await.ok();
    });

    (addr, state)
}

type WsStream = tokio_tungstenite::WebSocketStream<
    tokio_tungstenite::MaybeTlsStream<tokio::net::TcpStream>,
>;

async fn ws_connect(addr: SocketAddr) -> WsStream {
    let url = format!("ws://127.0.0.1:{}/ws", addr.port());
    connect_async(url).await.expect("WS connect").0
}

async fn send_json(ws: &mut WsStream, v: Value) {
    ws.send(WsMsg::Text(v.to_string().into()))
        .await
        .expect("WS send");
}

async fn recv_json(ws: &mut WsStream) -> Value {
    loop {
        let msg = ws.next().await.expect("stream ended").expect("WS recv");
        match msg {
            WsMsg::Text(t) => return serde_json::from_str(&t).expect("JSON parse"),
            WsMsg::Close(_) => panic!("connection closed before receiving expected frame"),
            _ => continue,
        }
    }
}

fn setup_agent(state: &Arc<AppState>, project: &str, project_key: &str, agent: &str) -> SigningKey {
    let signing_key = SigningKey::generate(&mut OsRng);
    let pubkey_hex = hex::encode(signing_key.verifying_key().to_bytes());
    state
        .broker
        .repo
        .register_project(project, project_key)
        .expect("register_project");
    state
        .broker
        .repo
        .register_agent(agent, project, "agent")
        .expect("register_agent");
    state
        .broker
        .repo
        .set_agent_public_key(agent, project, &pubkey_hex)
        .expect("set_agent_public_key");
    signing_key
}

async fn hello_and_get_challenge(
    ws: &mut WsStream,
    agent: &str,
    project: &str,
) -> (String, u64, String) {
    send_json(ws, json!({"type": "hello", "name": agent, "project": project})).await;
    let challenge = recv_json(ws).await;
    assert_eq!(challenge["type"], "challenge", "expected challenge frame");
    let nonce_hex = challenge["nonce"].as_str().unwrap().to_string();
    let timestamp = challenge["timestamp"].as_u64().unwrap();
    let session_id = challenge["session_id"].as_str().unwrap().to_string();
    (nonce_hex, timestamp, session_id)
}

fn sign_challenge(
    signing_key: &SigningKey,
    nonce_hex: &str,
    timestamp: u64,
    session_id: &str,
    agent: &str,
    project: &str,
) -> String {
    let nonce_bytes: [u8; 32] = hex::decode(nonce_hex)
        .expect("nonce hex")
        .try_into()
        .expect("nonce 32 bytes");
    let payload = crate::identity::build_challenge_payload(
        &nonce_bytes, timestamp, session_id, agent, project,
    );
    hex::encode(signing_key.sign(&payload).to_bytes())
}

async fn ws_auth_before_challenge_sends_protocol_error() {
    let (addr, _state) = spawn_test_server().await;
    let mut ws = ws_connect(addr).await;

    // Skip Hello ΓÇö send Auth immediately (protocol violation)
    send_json(&mut ws, json!({"type": "auth", "signature": "deadbeef"})).await;

    let resp = recv_json(&mut ws).await;
    assert_eq!(resp["type"], "error", "expected error frame, got: {resp}");
    assert_eq!(
        resp["error_code"], "PROTOCOL_ERROR",
        "expected PROTOCOL_ERROR, got: {resp}"
    );
}

async fn ws_expired_nonce_sends_auth_stale() {
    let (addr, state) = spawn_test_server().await;
    let signing_key = setup_agent(&state, "proj-stale", "key-stale", "Alice");

    let mut ws = ws_connect(addr).await;
    let (nonce_hex, timestamp, session_id) =
        hello_and_get_challenge(&mut ws, "Alice", "proj-stale").await;

    // Pre-drain the nonce ΓÇö simulates TTL expiry before Auth arrives
    let was_present = state.broker.nonce_store.consume(&nonce_hex);
    assert!(was_present.is_some(), "nonce must be in store after challenge issuance");

    // Send a correctly-signed Auth ΓÇö signature is valid, but nonce is gone
    let sig_hex = sign_challenge(&signing_key, &nonce_hex, timestamp, &session_id, "Alice", "proj-stale");
    send_json(&mut ws, json!({"type": "auth", "signature": sig_hex})).await;

    let resp = recv_json(&mut ws).await;
    assert_eq!(resp["type"], "error", "expected error frame, got: {resp}");
    assert_eq!(
        resp["error_code"], "AUTH_STALE",
        "expected AUTH_STALE for drained nonce, got: {resp}"
    );
}

async fn ws_wrong_key_sends_auth_wrong_key_and_burns_nonce() {
    let (addr, state) = spawn_test_server().await;
    let _correct_key = setup_agent(&state, "proj-badkey", "key-badkey", "Bob");

    let mut ws = ws_connect(addr).await;
    let (nonce_hex, timestamp, session_id) =
        hello_and_get_challenge(&mut ws, "Bob", "proj-badkey").await;

    // Sign with a DIFFERENT key ΓÇö not the registered one
    let wrong_key = SigningKey::generate(&mut OsRng);
    let sig_hex = sign_challenge(&wrong_key, &nonce_hex, timestamp, &session_id, "Bob", "proj-badkey");
    send_json(&mut ws, json!({"type": "auth", "signature": sig_hex})).await;

    // Broker sends AUTH_WRONG_KEY
    let resp = recv_json(&mut ws).await;
    assert_eq!(resp["type"], "error", "expected error frame, got: {resp}");
    assert_eq!(
        resp["error_code"], "AUTH_WRONG_KEY",
        "expected AUTH_WRONG_KEY for wrong private key, got: {resp}"
    );

    // Nonce is burned: server consumed it before calling verify_agent_signature.
    // Second consume must return None ΓÇö client must reconnect for a fresh challenge.
    let second = state.broker.nonce_store.consume(&nonce_hex);
    assert!(
        second.is_none(),
        "nonce must be burned after failed verify ΓÇö oracle attack prevention"
    );
}

pub struct DeliveryEngine {
    state: Arc<BrokerState>,
}

pub fn new(state: Arc<BrokerState>) -> Self {
        Self { state }
    }

pub async fn deliver(
        &self,
        id: &str,
        from_agent: &str,
        from_project: &str,
        to_agent: Option<&str>,
        to_channel: Option<&str>,
        body: &str,
        metadata: Option<&str>,
        mentions: &[ResolvedMention],
    ) -> Result<(), String> {
        let enriched_body = stanza::enrich_from(body, from_agent, from_project);
        let enriched_body = stanza::rewrite_mentions(&enriched_body, mentions);
        let enriched_body = enriched_body.as_str();

        self.state.repo.insert_message(id, from_agent, from_project, to_agent, to_channel, enriched_body, metadata)?;

        if let Some(target) = to_agent {
            let (name, project) = stanza::resolve_agent_name(target, from_project);
            self.deliver_to_agent(id, name, project, enriched_body).await?;
        }

        if let Some(channel) = to_channel {
            // Fan out to channel subscribers within the sender's project, recording delivery status
            let results = self.state.send_to_channel(channel, from_project, enriched_body, Some(from_agent)).await;
            for (sub_name, sub_project, delivered) in results {
                if delivered {
                    self.state.repo.record_delivered(id, &sub_name, &sub_project)?;
                } else {
                    self.state.repo.record_pending(id, &sub_name, &sub_project)?;
                }
            }

            self.deliver_to_mentions(id, from_agent, from_project, channel, enriched_body, mentions).await?;
        }

        Ok(())
    }

pub async fn deliver_to_cross_project_channel(
        &self,
        id: &str,
        from_agent: &str,
        from_project: &str,
        channel: &str,
        target_project: &str,
        body: &str,
        mentions: &[ResolvedMention],
    ) -> Result<(), String> {
        let enriched_body = stanza::enrich_from(body, from_agent, from_project);
        let enriched_body = stanza::rewrite_mentions(&enriched_body, mentions);
        let enriched_body = enriched_body.as_str();

        self.state.repo.insert_message(id, from_agent, from_project, None, Some(channel), enriched_body, None)?;

        let results = self.state.send_to_channel(channel, target_project, enriched_body, None).await;
        for (sub_name, sub_project, delivered) in results {
            if delivered {
                self.state.repo.record_delivered(id, &sub_name, &sub_project)?;
            } else {
                self.state.repo.record_pending(id, &sub_name, &sub_project)?;
            }
        }

        self.deliver_to_mentions(id, from_agent, from_project, channel, enriched_body, mentions).await?;
        Ok(())
    }

async fn deliver_to_mentions(
        &self,
        id: &str,
        from_agent: &str,
        from_project: &str,
        channel: &str,
        body: &str,
        mentions: &[ResolvedMention],
    ) -> Result<(), String> {
        if mentions.is_empty() {
            return Ok(());
        }

        let subscribers: std::collections::HashSet<(String, String)> = self
            .state
            .repo
            .get_subscribers(channel, from_project)
            .into_iter()
            .collect();

        for mention in mentions {
            let (mention_name, mention_project): (&str, &str) = match mention {
                ResolvedMention::SameProject { name } => (name.as_str(), from_project),
                ResolvedMention::CrossProject { name, project } => (name.as_str(), project.as_str()),
            };
            // Skip sender (qualified check ΓÇö avoids blocking a cross-project agent with the same name)
            // and agents already receiving the message as channel subscribers
            if (mention_name == from_agent && mention_project == from_project)
                || subscribers.contains(&(mention_name.to_string(), mention_project.to_string()))
            {
                continue;
            }
            // Auth check for cross-project mentions ΓÇö silently skip if denied
            if mention_project != from_project
                && !self.state.repo.is_cross_project_allowed(from_project, mention_project)
            {
                // ASSUMPTION: sender accepts silent skip on auth denial for implicitly-resolved
                // cross-project mentions. IF INVALID: replace with tracing::warn!(
                //   "Cross-project mention to {}.{} from {}.{} denied by auth table",
                //   mention_name, mention_project, from_agent, from_project) and continue.
                tracing::debug!(
                    "Cross-project mention to {}.{} denied by auth table",
                    mention_name, mention_project
                );
                continue;
            }
            if !self.state.repo.agent_exists(mention_name, mention_project) {
                continue;
            }
            // Avoid allocating for same-project mentions ΓÇö only cross-project delivery needs to= enrichment.
            let delivery_body = if mention_project != from_project {
                std::borrow::Cow::Owned(stanza::enrich_to_for_remote(body, channel, from_project))
            } else {
                std::borrow::Cow::Borrowed(body)
            };
            self.deliver_to_agent(id, mention_name, mention_project, &delivery_body).await?;
        }
        Ok(())
    }

async fn deliver_to_agent(
        &self,
        message_id: &str,
        name: &str,
        project: &str,
        body: &str,
    ) -> Result<(), String> {
        if self.state.send_to_agent(name, project, body).await {
            self.state.repo.record_delivered(message_id, name, project)?;
        } else {
            tracing::warn!("No live WS session for {}.{} ΓÇö message {} queued as pending", name, project, message_id);
            self.state.repo.record_pending(message_id, name, project)?;
        }
        Ok(())
    }

pub fn drain_pending(&self, name: &str, project: &str) -> Vec<PendingMessage> {
        self.state.repo.drain_pending(name, project)
    }

pub fn cleanup(&self, delivered_hours: u64, pending_hours: u64) -> (usize, usize) {
        self.state.repo.cleanup(delivered_hours, pending_hours)
    }

mod tests {
    use super::*;
    use crate::broker::state::BrokerState;
