pub struct NonceStore {
    inner: RwLock<HashMap<String, (Vec<u8>, Instant)>>,
}

impl NonceStore {
    pub fn new() -> Self {
        Self {
            inner: RwLock::new(HashMap::new()),
        }
    }

    /// Issue a new nonce: generate random bytes, build the canonical challenge payload,
    /// and store it keyed by nonce_hex with a TTL.
    ///
    /// Returns `(nonce_bytes, canonical_payload, timestamp_u64)`.
    /// The caller sends `nonce_hex` + `timestamp` + `session_id` in the Challenge envelope.
    /// The stored payload is retrieved by `consume()` at verify time.
    pub fn issue(
        &self,
        session_id: &str,
        name: &str,
        project: &str,
    ) -> ([u8; 32], Vec<u8>, u64) {
        let mut nonce = [0u8; 32];
        OsRng.fill_bytes(&mut nonce);

        let timestamp = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .unwrap_or_default()
            .as_secs();

        let payload =
            crate::identity::build_challenge_payload(&nonce, timestamp, session_id, name, project);

        let nonce_hex = hex::encode(nonce);
        let expires_at = Instant::now() + Duration::from_secs(NONCE_TTL_SECS);

        self.inner
            .write()
            .unwrap_or_else(|p| p.into_inner())
            .insert(nonce_hex, (payload.clone(), expires_at));

        (nonce, payload, timestamp)
    }

    /// Consume a nonce: return the stored canonical payload if the nonce exists and is not expired.
    /// Removes the nonce from the store regardless (even if expired ΓÇö prevents memory leak).
    /// Returns None if nonce is not found or expired.
    pub fn consume(&self, nonce_hex: &str) -> Option<Vec<u8>> {
        let mut store = self.inner.write().unwrap_or_else(|p| p.into_inner());
        match store.remove(nonce_hex) {
            Some((payload, expires_at)) if Instant::now() <= expires_at => Some(payload),
            _ => None,
        }
    }

    /// Evict all expired nonces. Called periodically from the cleanup loop.
    pub fn evict_expired(&self) {
        let now = Instant::now();
        self.inner
            .write()
            .unwrap_or_else(|p| p.into_inner())
            .retain(|_, (_, expires_at)| *expires_at > now);
    }
}

mod tests {
    use super::*;

    /// `consume()` after a failed verify burns the nonce ΓÇö second attempt returns None.
    ///
    /// Security invariant: the client MUST reconnect for a fresh challenge on any failed auth.
    /// This prevents an attacker from probing multiple signatures against the same nonce.
    #[test]
    fn consume_burns_nonce_regardless_of_verify_outcome() {
        let store = NonceStore::new();
        let (nonce_bytes, _payload, _ts) = store.issue("sess-1", "Alice", "proj");
        let nonce_hex = hex::encode(nonce_bytes);

        // First consume ΓÇö payload returned (caller will attempt verify_agent_signature)
        let first = store.consume(&nonce_hex);
        assert!(first.is_some(), "first consume must return the stored payload");

        // Simulate failed verify: caller got WrongKey, nonce is already gone.
        // Second consume must return None ΓÇö nonce is burned.
        let second = store.consume(&nonce_hex);
        assert!(second.is_none(), "second consume must return None ΓÇö nonce burned on first consume");
    }

    /// `consume()` on an unknown nonce returns None.
    #[test]
    fn consume_unknown_nonce_returns_none() {
        let store = NonceStore::new();
        assert!(store.consume("deadbeef").is_none(), "unknown nonce must return None");
    }

    /// `issue()` + `consume()` round-trip: payload matches.
    #[test]
    fn issue_and_consume_payload_matches() {
        let store = NonceStore::new();
        let (nonce_bytes, issued_payload, _ts) = store.issue("sess-2", "Bob", "my-proj");
        let nonce_hex = hex::encode(nonce_bytes);

        let consumed_payload = store.consume(&nonce_hex).expect("must return payload");
        assert_eq!(consumed_payload, issued_payload, "consumed payload must match issued payload");
    }
}

pub fn open(path: &Path) -> Result<Repository, String> {
    let conn = Connection::open(path)
        .map_err(|e| format!("Failed to open database: {e}"))?;

    conn.execute_batch("PRAGMA journal_mode=WAL; PRAGMA foreign_keys=ON;")
        .map_err(|e| format!("Failed to set pragmas: {e}"))?;

    schema::ensure_schema(&conn)?;
    migrate(&conn)?;

    Ok(Repository::new(conn))
}

pub fn open_memory() -> Result<Repository, String> {
    let conn = Connection::open_in_memory()
        .map_err(|e| format!("Failed to open in-memory database: {e}"))?;

    conn.execute_batch("PRAGMA foreign_keys=ON;")
        .map_err(|e| format!("Failed to set pragmas: {e}"))?;

    schema::ensure_schema(&conn)?;
    migrate(&conn)?;

    Ok(Repository::new(conn))
}

fn migrate(conn: &Connection) -> Result<(), String> {
    // Migration 1: channels composite PK
    // Detect old single-column PK: pragma_table_info returns one row per column with pk > 0
    let pk_count: i64 = conn
        .prepare("SELECT COUNT(*) FROM pragma_table_info('channels') WHERE pk > 0")
        .and_then(|mut s| s.query_row([], |r| r.get(0)))
        .unwrap_or(0);

    // If pk_count == 1, the old schema has a sole TEXT PRIMARY KEY ΓÇö migrate it
    if pk_count == 1 {
        conn.execute_batch("
            PRAGMA foreign_keys=OFF;
            BEGIN;

            CREATE TABLE channels_new (
                id          TEXT NOT NULL,
                project     TEXT NOT NULL,
                description TEXT NOT NULL DEFAULT '',
                created_utc TEXT NOT NULL DEFAULT (datetime('now')),
                PRIMARY KEY (id, project)
            );
            INSERT INTO channels_new SELECT id, COALESCE(project, ''), description, created_utc FROM channels;

            CREATE TABLE subscriptions_new (
                agent_name     TEXT NOT NULL,
                project        TEXT NOT NULL,
                channel_id     TEXT NOT NULL,
                subscribed_utc TEXT NOT NULL DEFAULT (datetime('now')),
                PRIMARY KEY (agent_name, project, channel_id),
                FOREIGN KEY (agent_name, project) REFERENCES agents(name, project),
                FOREIGN KEY (channel_id, project) REFERENCES channels_new(id, project)
            );
            INSERT INTO subscriptions_new SELECT agent_name, project, channel_id, subscribed_utc FROM subscriptions;

            DROP TABLE subscriptions;
            DROP TABLE channels;
            ALTER TABLE channels_new RENAME TO channels;
            ALTER TABLE subscriptions_new RENAME TO subscriptions;

            -- NEW-8: backfill any channel rows that existed only as subscription references
            -- (pre-CT-2 data may have subscriptions whose channel rows were lost in the migration).
            INSERT OR IGNORE INTO channels (id, project, created_utc)
            SELECT DISTINCT channel_id, project, datetime('now')
            FROM subscriptions
            WHERE (channel_id || '|' || project) NOT IN
                (SELECT id || '|' || project FROM channels);

            COMMIT;
            PRAGMA foreign_keys=ON;
        ").map_err(|e| format!("Channel schema migration failed: {e}"))?;
    }

    // Migration 2: seed default-allow ('*') for all projects registered before this migration.
    // INSERT OR IGNORE makes this idempotent ΓÇö safe to run on every startup.
    conn.execute_batch("
        INSERT OR IGNORE INTO cross_project_allowed_sources
        SELECT '*', name FROM projects;
    ").map_err(|e| format!("cross_project_allowed_sources backfill failed: {e}"))?;

    Ok(())
}

pub enum VerifyError {
    /// The public key bytes are not a valid Ed25519 key.
    InvalidPublicKey,
    /// The signature bytes are not a valid Ed25519 signature.
    InvalidSignature,
    /// The signature did not verify against the payload with the given key.
    WrongKey,
}

pub fn build_challenge_payload(
    nonce: &[u8; 32],
    timestamp: u64,
    session_id: &str,
    name: &str,
    project: &str,
) -> Vec<u8> {
    let mut payload = Vec::new();
    payload.extend_from_slice(nonce);
    payload.extend_from_slice(&timestamp.to_be_bytes());
    len_prefix(&mut payload, session_id);
    len_prefix(&mut payload, name);
    len_prefix(&mut payload, project);
    payload
}

fn len_prefix(buf: &mut Vec<u8>, s: &str) {
    let bytes = s.as_bytes();
    buf.extend_from_slice(&(bytes.len() as u16).to_be_bytes());
    buf.extend_from_slice(bytes);
}

pub fn verify_agent_signature(
    public_key_hex: &str,
    payload: &[u8],
    signature_hex: &str,
) -> Result<(), VerifyError> {
    let key_bytes: [u8; 32] = hex::decode(public_key_hex)
        .ok()
        .and_then(|b| b.try_into().ok())
        .ok_or(VerifyError::InvalidPublicKey)?;
    let verifying_key =
        VerifyingKey::from_bytes(&key_bytes).map_err(|_| VerifyError::InvalidPublicKey)?;

    let sig_bytes: [u8; 64] = hex::decode(signature_hex)
        .ok()
        .and_then(|b| b.try_into().ok())
        .ok_or(VerifyError::InvalidSignature)?;
    let signature = Signature::from_bytes(&sig_bytes);

    verifying_key
        .verify_strict(payload, &signature)
        .map_err(|_| VerifyError::WrongKey)
}

pub fn hash_key(key: &str) -> String {
    let mut hasher = Sha256::new();
    hasher.update(key.as_bytes());
    hex::encode(hasher.finalize())
}

pub fn verify_key_hash(key: &str, stored_hash: &str) -> bool {
    hash_key(key) == stored_hash
}

async fn main() {
    tracing_subscriber::fmt()
        .with_env_filter(
            tracing_subscriber::EnvFilter::try_from_default_env()
                .unwrap_or_else(|_| "agent_broker=info".into()),
        )
        .init();

    let port: u16 = std::env::var("BROKER_PORT")
        .ok()
        .and_then(|p| p.parse().ok())
        .unwrap_or(4200);

    let data_dir = std::env::var("BROKER_DATA")
        .map(PathBuf::from)
        .unwrap_or_else(|_| dirs_or_default());

    std::fs::create_dir_all(&data_dir).ok();

    let db_path = data_dir.join("agent-broker.db");
    tracing::info!("Data directory: {}", data_dir.display());

    let repo = Arc::new(db::open(&db_path).expect("Failed to open database"));
    let broker_state = Arc::new(BrokerState::new(repo));
    let delivery = Arc::new(DeliveryEngine::new(broker_state.clone()));

    // Periodic cleanup: delivered messages after 6h, pending after 7 days
    let cleanup_delivery = delivery.clone();
    tokio::spawn(async move {
        let mut interval = tokio::time::interval(std::time::Duration::from_secs(6 * 3600));
        loop {
            interval.tick().await;
            let (delivered, pending) = cleanup_delivery.cleanup(6, 168);
            if delivered > 0 || pending > 0 {
                tracing::info!("Cleanup: removed {delivered} delivered, {pending} expired pending messages");
            }
        }
    });

    // Nonce eviction: runs every 120s ΓÇö TTL is 60s, so at most 2 TTLs of stale entries accumulate
    let broker_state_for_cleanup = broker_state.clone();
    tokio::spawn(async move {
        let mut interval = tokio::time::interval(std::time::Duration::from_secs(120));
        loop {
            interval.tick().await;
            broker_state_for_cleanup.nonce_store.evict_expired();
        }
    });

    let config = api::routes::BrokerConfig {
        admin_key: std::env::var("BROKER_ADMIN_KEY").ok(),
        rate_limit_rps: std::env::var("RATE_LIMIT_RPS")
            .ok()
            .and_then(|v| v.parse().ok())
            .unwrap_or(100),
    };
    let rate_limiter = Arc::new(api::middleware::ProjectRateLimiter::new(config.rate_limit_rps));

    let app_state = Arc::new(AppState {
        broker: broker_state,
        delivery,
        config,
        rate_limiter,
    });

    let app = api::http_router(app_state.clone())
        .nest("/admin", api::admin_router())
        .route("/ws", axum::routing::get(api::handle_ws))
        .with_state(app_state);

    let addr = format!("127.0.0.1:{port}");
    tracing::info!("Agent broker listening on {addr}");

    let listener = tokio::net::TcpListener::bind(&addr)
        .await
        .expect("Failed to bind");

    axum::serve(listener, app).await.expect("Server error");
}

fn dirs_or_default() -> PathBuf {
    dirs::home_dir()
        .unwrap_or_else(|| PathBuf::from("."))
        .join(".agent-broker")
}

pub fn parse(text: &str) -> Result<Stanza, ParseError> {
    let trimmed = text.trim();
    if trimmed.starts_with("<message") {
        if !trimmed.ends_with("</message>") && !trimmed.ends_with("/>") {
            return Err(ParseError::Malformed("Missing closing </message> tag".into()));
        }
        parse_message(trimmed, text).map(Stanza::Message)
    } else if trimmed.starts_with("<presence") {
        if !trimmed.ends_with("</presence>") && !trimmed.ends_with("/>") {
            return Err(ParseError::Malformed("Missing closing </presence> tag".into()));
        }
        parse_presence(trimmed, text).map(Stanza::Presence)
    } else {
        Err(ParseError::NotAStanza)
    }
}

fn parse_message(xml: &str, raw: &str) -> Result<MessageStanza, ParseError> {
    let tag_end = xml.find('>').ok_or(ParseError::Malformed("No closing > on opening tag".into()))?;
    let attrs = parse_attrs(&xml[..tag_end]);

    let from = require_attr(&attrs, "from")?;
    let to = require_attr(&attrs, "to")?;
    let type_str = require_attr(&attrs, "type")?;
    let message_type = MessageType::from_str(&type_str).ok_or_else(|| ParseError::InvalidValue {
        attribute: "type".into(),
        value: type_str,
    })?;

    let mentions = attrs
        .get("mentions")
        .map(|v| v.split(',').map(|s| s.trim().to_string()).filter(|s| !s.is_empty()).collect())
        .unwrap_or_default();

    Ok(MessageStanza {
        from,
        to,
        message_type,
        mentions,
        raw: raw.to_string(),
    })
}

fn parse_presence(xml: &str, raw: &str) -> Result<PresenceStanza, ParseError> {
    let tag_end = xml.find('>').ok_or(ParseError::Malformed("No closing > on opening tag".into()))?;
    let attrs = parse_attrs(&xml[..tag_end]);

    let from = require_attr(&attrs, "from")?;
    let status_str = require_attr(&attrs, "status")?;
    let status = PresenceStatus::from_str(&status_str).ok_or_else(|| ParseError::InvalidValue {
        attribute: "status".into(),
        value: status_str,
    })?;

    Ok(PresenceStanza {
        from,
        status,
        raw: raw.to_string(),
    })
}

fn require_attr(
    attrs: &std::collections::HashMap<String, String>,
    name: &str,
) -> Result<String, ParseError> {
    attrs
        .get(name)
        .cloned()
        .ok_or_else(|| ParseError::MissingAttribute(name.into()))
}

fn parse_attrs(tag: &str) -> std::collections::HashMap<String, String> {
    ATTR_RE
        .captures_iter(tag)
        .map(|cap| (cap[1].to_string(), cap[2].to_string()))
        .collect()
}

